() => {
  const [searchTerm, setSearchTerm] = React.useState('');
  const [searchResults, setSearchResults] = React.useState([]);
  const handleChange = event => {
    setSearchTerm(event.target.value);
  };
  React.useEffect(() => {
    const listItems = ['List item 1', 'List item 2', 'List item 3', 'List item 4'];
    const results = listItems.filter(listItem => listItem.toLowerCase().includes(searchTerm.toLowerCase()));
    setSearchResults(results);
  }, [searchTerm]);
  return <ContainedList label="List title" kind="on-page" action={<ExpandableSearch placeholder="Filter" labelText="Search" value={searchTerm} onChange={handleChange} closeButtonLabelText="Clear search input" size="lg" />}>
      {searchResults.map((listItem, key) => <ContainedListItem key={key}>{listItem}</ContainedListItem>)}
    </ContainedList>;
}

